  2	import { useBucketOrigin } from '@odf/core/components/s3-browser/bucket-overview/useBucketOrigin';
  3	import {
  4	  BUCKET_BOOKMARKS_USER_SETTINGS_KEY,
  5	  LIST_VERSIONED_OBJECTS,
  6	} from '@odf/core/constants';
  7	import { ODF_ADMIN } from '@odf/core/features';
  8	import { useUserSettingsLocalStorage } from '@odf/shared';
  9	import { CommonModalProps } from '@odf/shared/modals';
 10	import { S3Commands } from '@odf/shared/s3';
 11	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 12	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 13	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 14	import { Trans } from 'react-i18next';
 15	import { useNavigate } from 'react-router-dom-v5-compat';
 16	import useSWR from 'swr';
 17	import {
 18	  Modal,
 19	  Button,
 20	  Text,
 21	  TextInput,
 22	  ModalVariant,
 23	  ValidatedOptions,
 24	  TextInputTypes,
 25	  TextVariants,
 26	  TextContent,
 27	  FormGroup,
 28	  Alert,
 29	  Spinner,
 30	  AlertVariant,
 31	  AlertActionLink,
 32	  ButtonVariant,
 33	} from '@patternfly/react-core';
 34	import { BUCKETS_BASE_ROUTE } from '../../../constants';
 35	import { EmptyBucketResponse, getTextInputLabel } from './EmptyBucketModal';
 36	import { LazyEmptyBucketModal } from './lazy-delete-and-empty-bucket';
 37	
 38	type DeleteBucketModalProps = {
 39	  bucketName: string;
 40	  s3Client: S3Commands;
 41	  launcher: LaunchModal;
 42	  refreshTokens?: () => void;
 43	  setEmptyBucketResponse: React.Dispatch<
 44	    React.SetStateAction<EmptyBucketResponse>
 45	  >;
 46	};
 47	
 48	const DeleteBucketModal: React.FC<CommonModalProps<DeleteBucketModalProps>> = ({
 49	  closeModal,
 50	  isOpen,
 51	  extraProps: {
 52	    bucketName,
 53	    s3Client,
 54	    launcher,
 55	    refreshTokens,
 56	    setEmptyBucketResponse,
 57	  },
 58	}) => {
 59	  const { t } = useCustomTranslation();
 60	  const [inputValue, setInputValue] = React.useState('');
 61	  const [inProgress, setInProgress] = React.useState(false);
 62	  const [deleteError, setDeleteError] = React.useState<Error>(null);
 63	
 64	  const navigate = useNavigate();
 65	
 66	  const {
 67	    data,
 68	    error,
 69	    isLoading: isChecking,
 70	  } = useSWR(
 71	    `${s3Client.providerType}-${bucketName}-${LIST_VERSIONED_OBJECTS}`,
 72	    () => s3Client.listObjectVersions({ Bucket: bucketName, MaxKeys: 1 })
 73	  );
 74	  const hasObjects =
 75	    data?.Versions?.length > 0 || data?.DeleteMarkers?.length > 0;
 76	
 77	  const [, setFavorites] = useUserSettingsLocalStorage<string[]>(
 78	    BUCKET_BOOKMARKS_USER_SETTINGS_KEY,
 79	    true,
 80	    []
 81	  );
 82	  const isAdmin = useFlag(ODF_ADMIN);
 83	  // "isCreatedByOBC" denotes whether bucket is created via OBC or S3 endpoint (will be false if we are inside folder view)
 84	  const { isCreatedByOBC } = useBucketOrigin(bucketName, null, isAdmin);
 85	
 86	  const onDelete = async (event) => {
 87	    event.preventDefault();
 88	    setInProgress(true);
 89	
 90	    try {
 91	      await s3Client.deleteBucket({
 92	        Bucket: bucketName,
 93	      });
