 98	        oldFavorites.filter((bucket) => bucket !== bucketName)
 99	      );
100	      refreshTokens?.();
101	      navigate(BUCKETS_BASE_ROUTE);
102	    } catch (err) {
103	      setDeleteError(err);
104	      setInProgress(false);
105	    }
106	  };
