125	            key="confirm"
126	            variant={ButtonVariant.danger}
127	            isLoading={inProgress}
128	            onClick={onDelete}
129	            isDisabled={inputValue !== bucketName || inProgress || hasObjects}
130	          >
131	            {t('Delete bucket')}
132	          </Button>
133	
134	          <Button
135	            key="cancel"
136	            variant={ButtonVariant.link}
137	            onClick={closeModal}
138	          >
139	            {t('Cancel')}
140	          </Button>
141	        </div>,
142	      ]}
143	    >
144	      {isChecking ? (
145	        <Spinner size="md" className="pf-v6-u-mb-md" />
146	      ) : (
147	        hasObjects && (
148	          <Alert
149	            variant={AlertVariant.danger}
150	            isInline
151	            title={t('Cannot delete this bucket: it is not empty')}
152	            className="co-alert pf-v6-u-mb-md"
153	            actionLinks={
154	              <AlertActionLink
155	                onClick={() =>
156	                  launcher(LazyEmptyBucketModal, {
157	                    isOpen: true,
158	                    extraProps: {
159	                      bucketName,
160	                      s3Client,
161	                      refreshTokens,
162	                      setEmptyBucketResponse,
163	                    },
164	                  })
165	                }
166	              >
167	                {t('Empty bucket')}
168	              </AlertActionLink>
169	            }
170	          >
171	            <p>
172	              <Trans t={t}>
173	                Bucket must be empty before it can be deleted. Use the{' '}
174	                <b>Empty bucket</b> configuration to erase all the contents i.e.{' '}
175	                <i>objects</i> of the bucket and try again.
176	              </Trans>
177	            </p>
178	          </Alert>
179	        )
180	      )}
181	      <TextContent className="text-muted">
182	        <Text component={TextVariants.p}>
183	          {t('Deleting a bucket cannot be undone.')}
184	        </Text>
185	        <Text component={TextVariants.p}>
186	          {t(
187	            'Bucket names are unique. If you delete a bucket, another S3 user can use the name.'
188	          )}
189	        </Text>
190	      </TextContent>
191	      {isCreatedByOBC && (
192	        <Alert
193	          title={t('Delete OBC')}
194	          variant={AlertVariant.warning}
195	          className="pf-v6-u-mt-md"
196	          isInline
197	        >
198	          {t(
199	            'NooBaa does not automatically delete the OBC if a bucket is deleted. Make sure you delete the corresponding OBC'
200	          )}
201	        </Alert>
202	      )}
203	
204	      <FormGroup
205	        label={getTextInputLabel(t, bucketName)}
206	        className="pf-v6-u-mt-2xl pf-v6-u-mb-sm"
207	        fieldId="delete-bucket"
208	      >
209	        <TextInput
210	          value={inputValue}
211	          type={TextInputTypes.text}
212	          onChange={(_event, value) => setInputValue(value)}
213	          aria-label={t('Bucket name input')}
214	          validated={
215	            inputValue === bucketName
216	              ? ValidatedOptions.success
217	              : ValidatedOptions.default
218	          }
219	          placeholder={bucketName}
220	        />
221	      </FormGroup>
222	      {(error || deleteError) && (
223	        <Alert
224	          variant={AlertVariant.danger}
225	          isInline
226	          title={t('Error')}
227	          className="pf-v6-u-mt-md"
228	        >
229	          {error?.message || deleteError?.message}
230	        </Alert>
231	      )}
232	    </Modal>
233	  );
234	};
235	
236	export default DeleteBucketModal;

